using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithSeedData();

        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = CreateContext();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            using var context = CreateContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.NotEmpty(model);
            Assert.All(model, g => Assert.True(g.StudentCount > 0));
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            using var context = CreateContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // We have students with 3 distinct enrollment dates in seed data
            var distinctDates = context.Students.Select(s => s.EnrollmentDate).Distinct().Count();
            Assert.Equal(distinctDates, model.Count);
        }

        [Fact]
        public void Contact_ReturnsViewWithMessage()
        {
            using var context = CreateContext();
            var controller = new HomeController(context);

            var result = controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            using var context = CreateContext();
            var controller = new HomeController(context);

            var result = controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            using var context = CreateContext();
            var controller = new HomeController(context);

            var result = controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private StudentsController CreateController(SchoolContext context)
        {
            var controller = new StudentsController(context);
            controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
            return controller;
        }

        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithSeedData();

        // ===== INDEX TESTS =====

        [Fact]
        public void Index_ReturnsViewWithPaginatedList()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n), names);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
