    public class InstructorsControllerTests
    {
        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithSeedData();

        // ===== INDEX TESTS =====

        [Fact]
        public void Index_NoSelection_ReturnsViewWithAllInstructors()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;
            var names = model.Instructors.Select(i => i.LastName).ToList();

            Assert.Equal(names.OrderBy(n => n), names);
        }

        [Fact]
        public void Index_WithInstructorId_SetsCourses()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructorId = 1; // Abercrombie

            var result = controller.Index(instructorId, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Courses);
            Assert.NotEmpty(model.Courses);
            Assert.Equal(instructorId, (int)controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_WithInstructorAndCourseId_SetsEnrollments()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            // Instructor 3 (Harui) teaches Course 1050 (Chemistry), which has enrollments
            var instructorId = 3;
            var courseId = 1050;

            var result = controller.Index(instructorId, courseId) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Enrollments);
            Assert.NotEmpty(model.Enrollments);
            Assert.Equal(courseId, (int)controller.ViewBag.CourseID);
        }

        // ===== DETAILS TESTS =====

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(1, instructor.ID);
        }

        // ===== CREATE GET TESTS =====

        [Fact]
        public void CreateGet_ReturnsViewWithNewInstructor()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void CreateGet_PopulatesAssignedCourseData()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            controller.Create();

            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(context.Courses.Count(), courses.Count);
            Assert.All(courses, c => Assert.False(c.Assigned));
        }

        // ===== CREATE POST TESTS =====

        [Fact]
        public void CreatePost_ValidInstructor_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = System.DateTime.Parse("2020-01-01")
            };

            var result = controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void CreatePost_ValidInstructor_SavesToDB()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var initialCount = context.Instructors.Count();
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = System.DateTime.Parse("2020-01-01")
            };

            controller.Create(instructor, null);

            Assert.Equal(initialCount + 1, context.Instructors.Count());
        }

        [Fact]
        public void CreatePost_WithSelectedCourses_AddsCourseAssignments()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = System.DateTime.Parse("2020-01-01")
            };
            var selectedCourses = new[] { "1050", "4022" };

            controller.Create(instructor, selectedCourses);

            var saved = context.Instructors.Include(Microsoft.EntityFrameworkCore.EntityFrameworkQueryableExtensions.Include)
                .FirstOrDefault(i => i.LastName == "Instructor");
            // Verify through the count of assignments
            Assert.Equal(2, instructor.CourseAssignments.Count);
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = System.DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        // ===== EDIT GET TESTS =====

        [Fact]
        public void EditGet_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void EditGet_ValidId_ReturnsViewWithInstructor()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(1, instructor.ID);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void EditGet_PopulatesAssignedCourseData()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            controller.Edit(1);

            var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(context.Courses.Count(), courses.Count);
            // Instructor 1 teaches Course 2021, so that should be assigned
            var compositionCourse = courses.SingleOrDefault(c => c.CourseID == 2021);
            Assert.NotNull(compositionCourse);
            Assert.True(compositionCourse.Assigned);
        }

        // ===== DELETE GET TESTS =====

        [Fact]
        public void DeleteGet_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void DeleteGet_InvalidId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteGet_ValidId_ReturnsViewWithInstructor()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(1, instructor.ID);
        }

        // ===== DELETE POST TESTS =====

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorFromDatabase()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var initialCount = context.Instructors.Count();

            controller.DeleteConfirmed(1);

            Assert.Equal(initialCount - 1, context.Instructors.Count());
            Assert.Null(context.Instructors.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            // Instructor 1 (Abercrombie) is administrator of Department 1 (English)

            controller.DeleteConfirmed(1);

            var department = context.Departments.Find(1);
            Assert.Null(department.InstructorID);
        }
    }
}
