using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private StudentsController CreateController(SchoolContext context)
        {
            var controller = new StudentsController(context);
            controller.TempData = new TempDataDictionary(new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
            return controller;
        }

        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithSeedData();

        // ===== INDEX TESTS =====

        [Fact]
        public void Index_ReturnsViewWithPaginatedList()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n), names);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderByDescending(n => n), names);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d), dates);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d), dates);
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersOnFirstName()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Carson", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_SetsPageTo1()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, null, "test", 3) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            controller.Index("Date", null, "test", null);

            Assert.Equal("Date", controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", controller.ViewBag.DateSortParm);
            Assert.Equal("", controller.ViewBag.NameSortParm);
            Assert.Equal("test", controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsNameSortParmToNameDesc()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            controller.Index(null, null, null, null);

            Assert.Equal("name_desc", controller.ViewBag.NameSortParm);
            Assert.Equal("Date", controller.ViewBag.DateSortParm);
        }

        // ===== DETAILS TESTS =====

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = CreateController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            using var context = CreateContext();
            var controller = CreateController(context);
            var studentId = context.Students.First().ID;

            var result = controller.Details(studentId) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(studentId, student.ID);
        }

        [Fact]
        public void Details_ValidId_IncludesEnrollments()
        {
            using var context = CreateContext();
            var controller = CreateController(context);
            // Student 1 has enrollments in seed data
            var result = controller.Details(1) as ViewResult;
            var student = result.Model as Student;

            Assert.NotNull(student.Enrollments);
            Assert.NotEmpty(student.Enrollments);
        }

        // ===== CREATE GET TESTS =====

        [Fact]
        public void CreateGet_ReturnsViewWithDefaultStudent()
