using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        private SchoolContext CreateContext() => TestDbContextFactory.CreateWithSeedData();

        // ===== INDEX TESTS =====

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var departments = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.NotEmpty(departments);
        }

        [Fact]
        public void Index_IncludesAdministrator()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Index() as ViewResult;
            var departments = result.Model as System.Collections.Generic.List<Department>;

            // All our seed departments have administrators
            Assert.All(departments, d => Assert.NotNull(d.Administrator));
        }

        // ===== DETAILS TESTS =====

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var deptId = context.Departments.First().DepartmentID;

            var result = controller.Details(deptId) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal(deptId, department.DepartmentID);
        }

        // ===== CREATE GET TESTS =====

        [Fact]
        public void CreateGet_ReturnsViewWithInstructorSelectList()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        // ===== CREATE POST TESTS =====

        [Fact]
        public void CreatePost_ValidDepartment_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = 1
            };

            var result = controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void CreatePost_ValidDepartment_SavesToDB()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var initialCount = context.Departments.Count();
            var department = new Department
            {
                Name = "Physics",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = 1
            };

            controller.Create(department);

            Assert.Equal(initialCount + 1, context.Departments.Count());
        }

        [Fact]
        public void CreatePost_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department();

            var result = controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        // ===== EDIT GET TESTS =====

        [Fact]
        public void EditGet_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void EditGet_InvalidId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void EditGet_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var deptId = context.Departments.First().DepartmentID;

            var result = controller.Edit(deptId) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal(deptId, department.DepartmentID);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        // ===== EDIT POST TESTS =====

        [Fact]
        public void EditPost_ValidDepartment_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var existing = context.Departments.First();
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var department = new Department
            {
                DepartmentID = existing.DepartmentID,
                Name = "Updated Dept",
                Budget = existing.Budget,
                StartDate = existing.StartDate,
                InstructorID = existing.InstructorID
            };

            var result = controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void EditPost_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { DepartmentID = 1 };

            var result = controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        // ===== DELETE GET TESTS =====

        [Fact]
        public void DeleteGet_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void DeleteGet_InvalidId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteGet_ValidId_ReturnsViewWithDepartment()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var deptId = context.Departments.First().DepartmentID;

            var result = controller.Delete(deptId) as ViewResult;

            Assert.NotNull(result);
            var department = Assert.IsType<Department>(result.Model);
            Assert.Equal(deptId, department.DepartmentID);
        }

        // ===== DELETE POST TESTS =====

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            // Use department 3 (Engineering) which might have fewer constraints
            var deptId = context.Departments.First().DepartmentID;

            var result = controller.DeleteConfirmed(deptId) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentFromDatabase()
        {
            using var context = CreateContext();
            var controller = new DepartmentsController(context);
            var deptId = context.Departments.First().DepartmentID;
            var initialCount = context.Departments.Count();

            controller.DeleteConfirmed(deptId);

            Assert.Equal(initialCount - 1, context.Departments.Count());
            Assert.Null(context.Departments.Find(deptId));
        }
    }
}

