1. using ContosoUniversity.Controllers;
2. using ContosoUniversity.Data;
3. using ContosoUniversity.Models;
4. using ContosoUniversity.Models.SchoolViewModels;
5. using ContosoUniversity.Tests.Helpers;
6. using Microsoft.AspNetCore.Mvc;
7. using System.Collections.Generic;
8. using System.Linq;
9. using Xunit;
10. 
11. namespace ContosoUniversity.Tests.Controllers
12. {
13.     public class InstructorsControllerTests
14.     {
15.         private SchoolContext CreateContext() => TestDbContextFactory.CreateWithSeedData();
16. 
17.         // ===== INDEX TESTS =====
18. 
19.         [Fact]
20.         public void Index_NoSelection_ReturnsViewWithAllInstructors()
21.         {
22.             using var context = CreateContext();
23.             var controller = new InstructorsController(context);
24. 
25.             var result = controller.Index(null, null) as ViewResult;
26. 
27.             Assert.NotNull(result);
28.             var model = Assert.IsType<InstructorIndexData>(result.Model);
29.             Assert.NotNull(model.Instructors);
30.             Assert.Equal(3, model.Instructors.Count());
31.         }
32. 
33.         [Fact]
34.         public void Index_InstructorsOrderedByLastName()
35.         {
36.             using var context = CreateContext();
37.             var controller = new InstructorsController(context);
38. 
39.             var result = controller.Index(null, null) as ViewResult;
40.             var model = result.Model as InstructorIndexData;
41.             var names = model.Instructors.Select(i => i.LastName).ToList();
42. 
43.             Assert.Equal(names.OrderBy(n => n), names);
44.         }
45. 
46.         [Fact]
47.         public void Index_WithInstructorId_SetsCourses()
48.         {
49.             using var context = CreateContext();
50.             var controller = new InstructorsController(context);
51.             var instructorId = 1; // Abercrombie
52. 
53.             var result = controller.Index(instructorId, null) as ViewResult;
54.             var model = result.Model as InstructorIndexData;
55. 
56.             Assert.NotNull(model.Courses);
57.             Assert.NotEmpty(model.Courses);
58.             Assert.Equal(instructorId, (int)controller.ViewBag.InstructorID);
59.         }
60. 
61.         [Fact]
62.         public void Index_WithInstructorAndCourseId_SetsEnrollments()
63.         {
64.             using var context = CreateContext();
65.             var controller = new InstructorsController(context);
66.             // Instructor 3 (Harui) teaches Course 1050 (Chemistry), which has enrollments
67.             var instructorId = 3;
68.             var courseId = 1050;
69. 
70.             var result = controller.Index(instructorId, courseId) as ViewResult;
71.             var model = result.Model as InstructorIndexData;
72. 
73.             Assert.NotNull(model.Enrollments);
74.             Assert.NotEmpty(model.Enrollments);
75.             Assert.Equal(courseId, (int)controller.ViewBag.CourseID);
76.         }
77. 
78.         // ===== DETAILS TESTS =====
79. 
80.         [Fact]
81.         public void Details_NullId_ReturnsBadRequest()
82.         {
83.             using var context = CreateContext();
84.             var controller = new InstructorsController(context);
85. 
86.             var result = controller.Details(null) as StatusCodeResult;
87. 
88.             Assert.NotNull(result);
89.             Assert.Equal(400, result.StatusCode);
90.         }
91. 
92.         [Fact]
93.         public void Details_InvalidId_ReturnsNotFound()
94.         {
95.             using var context = CreateContext();
