            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructorId, instructor.ID);
        }

        // ===== DELETE POST TESTS =====

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructorId = context.Instructors.First().ID;

            var result = controller.DeleteConfirmed(instructorId) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorFromDatabase()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var instructorId = context.Instructors.First().ID;
            var initialCount = context.Instructors.Count();

            controller.DeleteConfirmed(instructorId);

            Assert.Equal(initialCount - 1, context.Instructors.Count());
            Assert.Null(context.Instructors.Find(instructorId));
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            using var context = CreateContext();
            var controller = new InstructorsController(context);
            var abercrombie = context.Instructors.First(i => i.LastName == "Abercrombie");
            var englishDept = context.Departments.First(d => d.Name == "English");

            controller.DeleteConfirmed(abercrombie.ID);

            context.Entry(englishDept).Reload();
            Assert.Null(englishDept.InstructorID);
        }
    }
}

