using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanCreateInMemoryDatabase()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var assignment = context.CourseAssignments.First();
            Assert.NotEqual(0, assignment.CourseID);
            Assert.NotEqual(0, assignment.InstructorID);
        }

        [Fact]
        public void SchoolContext_InstructorOfficeAssignment_OneToOne()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var instructorWithOffice = context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.OfficeAssignment != null);

            Assert.NotNull(instructorWithOffice.OfficeAssignment);
            Assert.Equal(instructorWithOffice.ID, instructorWithOffice.OfficeAssignment.InstructorID);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveNotification()
        {
            using var context = TestDbContextFactory.Create();

            context.Notifications.Add(new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = System.DateTime.Now,
                CreatedBy = "System"
            });
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }

        [Fact]
        public void SchoolContext_TPH_StudentsAndInstructorsSharePeopleTable()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var totalPeople = context.People.Count();
            var students = context.Students.Count();
            var instructors = context.Instructors.Count();

            Assert.Equal(students + instructors, totalPeople);
        }

        [Fact]
        public void SchoolContext_Course_DepartmentRelationship()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var course = context.Courses.Include(c => c.Department).First();

            Assert.NotNull(course.Department);
            Assert.Equal(course.DepartmentID, course.Department.DepartmentID);
        }

        [Fact]
        public void SchoolContext_Enrollment_Relationships()
        {
            using var context = TestDbContextFactory.CreateWithSeedData();

            var enrollment = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();

            Assert.NotNull(enrollment.Student);
            Assert.NotNull(enrollment.Course);
        }
    }
}

